import { createReactAgent } from "@langchain/langgraph/prebuilt";
import { ChatGoogleGenerativeAI } from "@langchain/google-genai";
import { PROMPTS } from "./prompts";
import { documentSearchTool, getFundingInfoTool } from "./tools";

const executorLLM = new ChatGoogleGenerativeAI({
  model: "gemini-2.5-flash",
  temperature: 0.1,
});

const executorAgent = createReactAgent({
  llm: executorLLM,
  tools: [documentSearchTool, getFundingInfoTool],
  prompt: PROMPTS.executor,
});

export class SovereignExecutor {
  name = "sovereign_executor";

  async process(query: string, state: any) {
    const result = await executorAgent.invoke({
      messages: [{ role: "user", content: query }],
    });

    const lastMessage = result.messages[result.messages.length - 1];
    let content = typeof lastMessage.content === 'string'
      ? lastMessage.content
      : JSON.stringify(lastMessage.content);

    // Extract tool calls to flag for review if templates are generated
    const toolMessages = result.messages.filter((m: any) => m._getType && m._getType() === 'tool');

    return {
      content,
      agentUsed: this.name,
      requiresHumanReview: true, // We always flag execution for human review to ensure templates are safe
      confidence: 0.85,
      sources: [],
      metadata: {
        toolCalls: toolMessages.length > 0 ? toolMessages : [],
      },
    };
  }
}

'use client';

import { useState, useEffect } from 'react';
import { encrypt, decrypt } from '@/lib/encryption';

export default function PractitionerDashboard() {
  const [notes, setNotes] = useState<any[]>([]);
  const [patientRef, setPatientRef] = useState('');
  const [content, setContent] = useState('');
  const [passphrase, setPassphrase] = useState('');
  const [isUnlocked, setIsUnlocked] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState('');

  // Fetch encrypted notes on mount
  useEffect(() => {
    async function fetchNotes() {
      try {
        const res = await fetch('/api/practitioner/notes');
        const data = await res.json();
        if (data.notes) {
          setNotes(data.notes);
        }
      } catch (err) {
        console.error('Failed to fetch notes', err);
      }
    }
    fetchNotes();
  }, []);

  const handleUnlock = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    try {
      // Attempt to decrypt the first note as a test
      if (notes.length > 0) {
        const testNote = notes[0];
        const payload = JSON.parse(testNote.encrypted_content);
        await decrypt(payload, passphrase);
      }
      setIsUnlocked(true);
    } catch (err) {
      setError('Invalid passphrase. Unable to decrypt notes.');
    }
  };

  const handleSaveNote = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!isUnlocked) return;
    setIsLoading(true);
    setError('');

    try {
      // Encrypt the content locally
      const encryptedPayload = await encrypt(content, passphrase);

      const res = await fetch('/api/practitioner/notes', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          patient_reference: patientRef,
          encrypted_content: JSON.stringify(encryptedPayload)
        }),
      });

      if (!res.ok) throw new Error('Failed to save note');

      const { note } = await res.json();
      setNotes([note, ...notes]);
      setPatientRef('');
      setContent('');
    } catch (err: any) {
      setError(err.message);
    } finally {
      setIsLoading(false);
    }
  };

  const DecryptedNote = ({ note }: { note: any }) => {
    const [decryptedText, setDecryptedText] = useState('Decrypting...');

    useEffect(() => {
      if (isUnlocked) {
        try {
          const payload = JSON.parse(note.encrypted_content);
          decrypt(payload, passphrase).then(setDecryptedText).catch(() => setDecryptedText('Decryption failed'));
        } catch (err) {
          setDecryptedText('Invalid encrypted payload');
        }
      }
    }, [note, isUnlocked]);

    return <p className="text-gray-700 whitespace-pre-wrap">{decryptedText}</p>;
  };

  if (!isUnlocked) {
    return (
      <div className="p-8 max-w-xl mx-auto">
        <h1 className="text-3xl font-bold mb-4 text-gray-900">Practitioner Vault</h1>
        <p className="text-gray-600 mb-8">Enter your Taonga Vault passphrase to unlock and decrypt your patient notes locally. We never store this passphrase.</p>

        <form onSubmit={handleUnlock} className="bg-white p-6 rounded-xl shadow-sm border border-gray-200">
          {error && <div className="mb-4 text-red-600 text-sm">{error}</div>}
          <div className="mb-4">
            <label className="block text-sm font-medium text-gray-700 mb-1">Passphrase</label>
            <input 
              type="password" 
              required
              value={passphrase} 
              onChange={e => setPassphrase(e.target.value)}
              className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500"
            />
          </div>
          <button type="submit" className="w-full bg-blue-600 text-white font-medium py-3 rounded-lg hover:bg-blue-700">
            Unlock Vault
          </button>
        </form>
      </div>
    );
  }

  return (
    <div className="p-8 max-w-5xl mx-auto grid gap-8 md:grid-cols-2">
      <div>
        <h1 className="text-3xl font-bold mb-8 text-gray-900">Patient Notes</h1>

        <form onSubmit={handleSaveNote} className="bg-white p-6 rounded-xl shadow-sm border border-gray-200 mb-8">
          <h2 className="text-xl font-bold text-gray-900 mb-4">New Encrypted Note</h2>
          {error && <div className="mb-4 text-red-600 text-sm">{error}</div>}

          <div className="mb-4">
            <label className="block text-sm font-medium text-gray-700 mb-1">Patient Reference (Plaintext)</label>
            <input 
              type="text" 
              value={patientRef} 
              onChange={e => setPatientRef(e.target.value)}
              placeholder="e.g. Patient A"
              className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500"
            />
          </div>

          <div className="mb-4">
            <label className="block text-sm font-medium text-gray-700 mb-1">Clinical Note (Encrypted locally)</label>
            <textarea 
              required
              rows={5}
              value={content} 
              onChange={e => setContent(e.target.value)}
              className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500"
            />
          </div>

          <button 
            type="submit" 
            disabled={isLoading}
            className="w-full bg-blue-600 text-white font-medium py-3 rounded-lg hover:bg-blue-700 disabled:opacity-50"
          >
            {isLoading ? 'Encrypting & Saving...' : 'Save Securely'}
          </button>
        </form>
      </div>

      <div className="space-y-6">
        <h2 className="text-2xl font-bold text-gray-900 mb-2">Saved Notes</h2>
        {notes.length === 0 ? (
          <div className="text-gray-500">No notes found.</div>
        ) : (
          notes.map(note => (
            <div key={note.id} className="bg-white p-6 rounded-xl shadow-sm border border-gray-200">
              <div className="flex justify-between items-center mb-4 border-b pb-2">
                <h3 className="font-bold text-gray-900">{note.patient_reference || 'Unnamed Note'}</h3>
                <span className="text-xs text-gray-500">{new Date(note.created_at).toLocaleString()}</span>
              </div>
              <DecryptedNote note={note} />
            </div>
          ))
        )}
      </div>
    </div>
  );
}

'use client';

import { useState, useEffect } from 'react';
import ReactMarkdown from 'react-markdown';

interface FeedbackItem {
  id: string;
  thread_id: string;
  message_content: string;
  rating: number;
  comment: string;
  created_at: string;
}

export default function FeedbackDashboard() {
  const [feedbackList, setFeedbackList] = useState<FeedbackItem[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    async function fetchFeedback() {
      try {
        const res = await fetch('/api/practitioner/feedback');
        if (!res.ok) throw new Error('Failed to fetch feedback');
        const data = await res.json();
        setFeedbackList(data.feedback || []);
      } catch (err: any) {
        setError(err.message);
      } finally {
        setIsLoading(false);
      }
    }
    fetchFeedback();
  }, []);

  const totalFeedback = feedbackList.length;
  const positiveFeedback = feedbackList.filter(f => f.rating === 1).length;
  const negativeFeedback = feedbackList.filter(f => f.rating === -1).length;
  const positivePercentage = totalFeedback > 0 ? Math.round((positiveFeedback / totalFeedback) * 100) : 0;

  if (isLoading) {
    return (
      <div className="flex items-center justify-center min-h-[60vh]">
        <div className="w-8 h-8 bg-blue-600 rounded-full animate-pulse" />
      </div>
    );
  }

  return (
    <div className="max-w-7xl mx-auto px-6 py-10">
      <div className="mb-10">
        <h1 className="text-4xl font-bold text-gray-900 tracking-tight">Beta Feedback Analysis</h1>
        <p className="text-lg text-gray-600 mt-2">Monitor AI performance and review user feedback in real-time.</p>
      </div>

      {error && (
        <div className="bg-red-50 border-l-4 border-red-500 p-4 mb-8 rounded-r-lg">
          <p className="text-red-700">{error}</p>
        </div>
      )}

      {/* Metrics Cards */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-12">
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 flex items-center justify-between">
          <div>
            <p className="text-sm font-medium text-gray-500 uppercase tracking-wider">Total Feedback</p>
            <p className="text-4xl font-bold text-gray-900 mt-2">{totalFeedback}</p>
          </div>
          <div className="w-12 h-12 bg-blue-50 text-blue-600 rounded-xl flex items-center justify-center text-2xl">
            📊
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 flex items-center justify-between">
          <div>
            <p className="text-sm font-medium text-gray-500 uppercase tracking-wider">Positive Rating</p>
            <p className="text-4xl font-bold text-emerald-600 mt-2">{positivePercentage}%</p>
          </div>
          <div className="w-12 h-12 bg-emerald-50 text-emerald-600 rounded-xl flex items-center justify-center text-2xl">
            👍
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 flex items-center justify-between">
          <div>
            <p className="text-sm font-medium text-gray-500 uppercase tracking-wider">Needs Improvement</p>
            <p className="text-4xl font-bold text-rose-600 mt-2">{negativeFeedback}</p>
          </div>
          <div className="w-12 h-12 bg-rose-50 text-rose-600 rounded-xl flex items-center justify-center text-2xl">
            👎
          </div>
        </div>
      </div>

      {/* Feedback List */}
      <div>
        <h2 className="text-2xl font-bold text-gray-900 mb-6">Recent User Feedback</h2>
        {feedbackList.length === 0 ? (
          <div className="bg-gray-50 border border-dashed border-gray-300 rounded-2xl p-12 text-center">
            <p className="text-gray-500 text-lg">No feedback has been submitted yet.</p>
          </div>
        ) : (
          <div className="space-y-6">
            {feedbackList.map((item) => (
              <div key={item.id} className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
                <div className="border-b border-gray-50 px-6 py-4 flex items-center justify-between bg-gray-50/50">
                  <div className="flex items-center gap-3">
                    <span className={`px-3 py-1 text-sm font-bold rounded-full ${item.rating === 1 ? 'bg-emerald-100 text-emerald-700' : 'bg-rose-100 text-rose-700'}`}>
                      {item.rating === 1 ? 'Helpful 👍' : 'Not Helpful 👎'}
                    </span>
                    <span className="text-sm text-gray-500 font-mono">Thread: {item.thread_id.substring(0, 15)}...</span>
                  </div>
                  <span className="text-sm text-gray-400">
                    {new Date(item.created_at).toLocaleString()}
                  </span>
                </div>

                <div className="p-6">
                  {item.comment && (
                    <div className="mb-4 bg-amber-50 p-4 rounded-xl border border-amber-100">
                      <p className="text-sm font-semibold text-amber-900 mb-1">User Comment:</p>
                      <p className="text-amber-800 italic">"{item.comment}"</p>
                    </div>
                  )}

                  <div>
                    <p className="text-sm font-semibold text-gray-900 mb-2">AI Response Context:</p>
                    <div className="prose prose-sm max-w-none text-gray-600 bg-gray-50 p-4 rounded-xl border border-gray-100 max-h-48 overflow-y-auto">
                      <ReactMarkdown>{item.message_content || '*No content recorded*'}</ReactMarkdown>
                    </div>
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}

