import { NextRequest } from 'next/server';
import { agentGraph } from '@/ai/graph';
import { HumanMessage, AIMessage } from '@langchain/core/messages';
import { routeLogger } from '@/lib/logger';
import { aiCircuitBreaker } from '@/lib/circuit-breaker';
import * as Sentry from '@sentry/nextjs';

const log = routeLogger('/api/agents');
import { createClient } from '@/lib/supabase/server';
import { checkRateLimit } from '@/ai/security';
import { AgentQuerySchema } from '@/lib/validations';



type ChatHistoryMessage = {
  role: 'user' | 'assistant';
  content: string;
};

function isChatHistoryMessage(value: unknown): value is ChatHistoryMessage {
  if (!value || typeof value !== 'object') return false;
  const candidate = value as Record<string, unknown>;
  return (
    (candidate.role === 'user' || candidate.role === 'assistant') &&
    typeof candidate.content === 'string'
  );
}

export async function POST(request: NextRequest) {
  // 1. IP-based Rate Limiting (10 requests per minute)
  const ip = request.headers.get('x-forwarded-for') || 'unknown_ip';
  const isAllowed = await checkRateLimit(ip, 10, 60000);
  if (!isAllowed) {
    log.warn({ ip }, 'Rate limit exceeded');
    return new Response(JSON.stringify({ error: 'Too Many Requests' }), { status: 429 });
  }

  try {
    const rawBody = await request.json();
    const parsed = AgentQuerySchema.safeParse(rawBody);

    if (!parsed.success) {
      return new Response(JSON.stringify({ error: 'Invalid Input', details: parsed.error }), { status: 400 });
    }

    const { 
      query, 
      consentGiven = true, 
      threadId = `thread_${Date.now()}`,
      history = []
    } = parsed.data;

    // Convert history into LangChain messages, limiting to the last 10 to save tokens
    const safeHistory = (Array.isArray(history) ? history.filter(isChatHistoryMessage) : []).slice(-10);

    const previousMessages = safeHistory.map((msg) =>
      msg.role === 'user'
        ? new HumanMessage(msg.content)
        : new AIMessage(msg.content)
    );

    // 2. AbortController Timeout (30 seconds)
    const abortController = new AbortController();
    const timeoutId = setTimeout(() => abortController.abort(), 30000);

    const stream = new ReadableStream({
      async start(controller) {
        const encoder = new TextEncoder();
        const startTime = Date.now();

        try {
          const runGraph = async () => {
            return await agentGraph.streamEvents(
              {
                query,
                consentGiven,
                messages: [...previousMessages, new HumanMessage(query)],
              },
              {
                version: 'v2',
                configurable: { thread_id: threadId },
                signal: abortController.signal
              }
            );
          };

          const eventStream = await aiCircuitBreaker.fire(runGraph).catch((cbError: any) => {
            if (cbError.message && cbError.message.includes('OPEN')) {
              throw new Error('CIRCUIT_OPEN');
            }
            throw cbError;
          });

          for await (const event of eventStream) {
            if (event.event === 'on_chat_model_stream') {
              const content = event.data?.chunk?.content;
              if (content) {
                controller.enqueue(
                  encoder.encode(`data: ${JSON.stringify({ type: 'token', content })}\n\n`)
                );
              }
            }

            if (event.event === 'on_chain_end' && event.name === 'agentGraph') {
              const finalState = event.data?.output;
              controller.enqueue(
                encoder.encode(
                  `data: ${JSON.stringify({
                    type: 'final',
                    agent: finalState?.currentAgent,
                    requiresHumanReview: finalState?.requiresHumanReview,
                    showUrgentHelp: finalState?.showUrgentHelp,
                    sources: finalState?.sources,
                  })}\n\n`
                )
              );

              const durationMs = Date.now() - startTime;
              createClient().then(supabase => {
                supabase.from('analytics_events').insert({
                  event_type: 'agent_latency',
                  path: '/api/agents',
                  session_hash: threadId,
                  metadata: { agent: finalState?.currentAgent, durationMs }
                }).then(() => {});
              });
            }
          }

          controller.enqueue(encoder.encode('data: [DONE]\n\n'));
        } catch (error: any) {
          // Handle LangGraph Interrupt
          if (error && (error.name === 'Interrupt' || error.name === 'GraphInterrupt')) {
            // Extract the proposed response from the interrupt value
            const interruptValue = error.value || error.interrupt || {};
            const proposedResponse = interruptValue.proposedResponse || '';

            // Insert pending review into Supabase
            try {
              const supabase = await createClient();
              await supabase.from('ai_reviews').insert({
                thread_id: threadId,
                query: query,
                proposed_response: proposedResponse,
                status: 'pending',
              });
            } catch (dbErr) {
              log.error({ err: dbErr, threadId }, 'Failed to save ai_review');
            }

            log.info({ threadId }, 'LangGraph interrupted for Human-in-the-Loop review');

            controller.enqueue(
              encoder.encode(
                `data: ${JSON.stringify({
                  type: 'interrupt',
                  message: 'This response requires human review before being sent.',
                  threadId,
                  requiresHumanReview: true,
                  proposedResponse,
                })}\n\n`
              )
            );
          } else if (error.name === 'AbortError') {
            log.error({ threadId }, 'Agent execution timed out after 30 seconds');
            controller.enqueue(
              encoder.encode(`data: ${JSON.stringify({ 
                type: 'error', 
                content: 'The request timed out. Please try again.' 
              })}\n\n`)
            );
          } else if (error.message === 'CIRCUIT_OPEN') {
            log.error({ threadId }, 'Circuit Breaker Open - System under high load');
            controller.enqueue(
              encoder.encode(`data: ${JSON.stringify({ 
                type: 'error', 
                content: 'The system is experiencing high volume. Please try again later.' 
              })}\n\n`)
            );
          } else {
            // Generic error
            log.error({ err: error, threadId }, 'Streaming error');
            Sentry.captureException(error, {
              tags: { component: 'agent_graph', threadId }
            });
            createClient().then(supabase => {
              supabase.from('analytics_events').insert({
                event_type: 'agent_error',
                path: '/api/agents',
                session_hash: threadId,
                metadata: { error: error.message || 'Generic error' }
              }).then(() => {});
            });
            controller.enqueue(
              encoder.encode(`data: ${JSON.stringify({ 
                type: 'error', 
                content: 'An error occurred during streaming.' 
              })}\n\n`)
            );
          }
        } finally {
          clearTimeout(timeoutId);
          controller.close();
        }
      },
    });

    return new Response(stream, {
      headers: {
        'Content-Type': 'text/event-stream',
        'Cache-Control': 'no-cache',
        Connection: 'keep-alive',
      },
    });

  } catch (error) {
    log.error({ err: error }, 'API error');
    Sentry.captureException(error, { tags: { route: '/api/agents' } });
    return new Response(JSON.stringify({ error: 'Internal server error' }), { status: 500 });
  }
}

import { NextRequest, NextResponse } from 'next/server';
import { ChatGoogleGenerativeAI } from '@langchain/google-genai';
import { SystemMessage, HumanMessage } from '@langchain/core/messages';

export async function POST(req: NextRequest) {
  try {
    const { history } = await req.json();

    if (!history || !Array.isArray(history)) {
      return NextResponse.json({ error: 'Missing or invalid history' }, { status: 400 });
    }

    const llm = new ChatGoogleGenerativeAI({
      model: 'gemini-2.5-flash',
      temperature: 0.1,
    });

    const systemPrompt = `
You are a clinical synthesis AI assistant for a NICU app.
Your task is to review the following chat history between a parent and an AI support system, and generate a clear, objective clinical summary designed to be handed to a doctor or NICU nurse.

Please format your summary using standard Markdown. Include the following sections if relevant information is present:
- **Patient Context:** (Any mentioned age, conditions, etc.)
- **Primary Concerns:** (What the parent is worried about)
- **Key Symptoms / Observations:** (e.g., temperature, lethargy, feeding issues)
- **Feeding/Care Updates:** (Relevant context about feeding methods or recent changes)

Keep it highly concise, professional, and objective. Exclude casual chat, greetings, and emotional processing unless it represents a clinical concern (e.g., severe maternal distress). Do not invent information; if a section has no data, omit it.
`;

    // Combine history into a single text block
    const conversationText = history
      .map((msg: any) => `${msg.role.toUpperCase()}: ${msg.content}`)
      .join('\n\n');

    const response = await llm.invoke([
      new SystemMessage(systemPrompt),
      new HumanMessage(`Here is the conversation history:\n\n${conversationText}`)
    ]);

    return NextResponse.json({ summary: response.content });

  } catch (error: any) {
    console.error('Failed to generate summary:', error);
    return NextResponse.json({ error: error.message || 'Internal Server Error' }, { status: 500 });
  }
}

import { NextRequest, NextResponse } from 'next/server';
import { createClient } from '@/lib/supabase/server';

export async function POST(req: NextRequest) {
  try {
    const supabase = await createClient();

    // Verify user
    const { data: { user }, error: userError } = await supabase.auth.getUser();
    if (userError || !user) {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
    }

    // Verify role is admin
    const { data: profile } = await supabase
      .from('profiles')
      .select('role')
      .eq('id', user.id)
      .single();

    if (profile?.role !== 'admin') {
      return NextResponse.json({ error: 'Forbidden. Admin access required.' }, { status: 403 });
    }

    const body = await req.json();
    const { id } = body;

    if (!id) {
      return NextResponse.json({ error: 'Listing ID is required' }, { status: 400 });
    }

    const { data, error } = await supabase
      .from('directory_listings')
      .update({ is_verified: true })
      .eq('id', id)
      .select()
      .single();

    if (error) {
      console.error('Error approving directory listing:', error);
      return NextResponse.json({ error: 'Failed to approve listing.' }, { status: 500 });
    }

    return NextResponse.json({ success: true, listing: data });
  } catch (err: any) {
    console.error('API Route Error:', err);
    return NextResponse.json({ error: 'Internal Server Error' }, { status: 500 });
  }
}

import { NextResponse, NextRequest } from 'next/server';
import { createClient } from '@/lib/supabase/server';
import { checkRateLimit, createAuditLog } from '@/ai/security';

export async function GET(req: NextRequest) {
  const ip = req.headers.get('x-forwarded-for') || 'unknown_ip';
  const isAllowed = await checkRateLimit(ip, 10, 60000);
  if (!isAllowed) {
    return new NextResponse('Too Many Requests', { status: 429 });
  }

  createAuditLog('FEEDBACK_EXPORT', { ip });

  try {
    const supabase = await createClient();
    const { data: feedbacks, error } = await supabase
      .from('ai_feedback')
      .select('*')
      .order('created_at', { ascending: false });

    if (error) {
      console.error('Error fetching feedback for export:', error);
      return NextResponse.json({ error: 'Failed to fetch data' }, { status: 500 });
    }

    // Convert to CSV
    const headers = ['id', 'created_at', 'rating', 'message_content', 'thread_id'];
    const csvRows = [headers.join(',')];

    for (const fb of feedbacks || []) {
      const values = headers.map(header => {
        const val = fb[header as keyof typeof fb];
        const escaped = ('' + val).replace(/"/g, '""');
        return `"${escaped}"`;
      });
      csvRows.push(values.join(','));
    }

    const csvString = csvRows.join('\n');

    return new NextResponse(csvString, {
      headers: {
        'Content-Type': 'text/csv',
        'Content-Disposition': 'attachment; filename="feedback_export.csv"',
      },
    });
  } catch (err) {
    return NextResponse.json({ error: 'Internal Server Error' }, { status: 500 });
  }
}

import { NextResponse } from 'next/server';
import { createClient } from '@supabase/supabase-js';
import { logger } from '@/lib/logger';
import { FeedbackSchema } from '@/lib/validations';
import { RateLimiter } from '@/lib/rate-limit';

const rateLimiter = new RateLimiter(60000, 10); // 10 feedback posts per minute

export async function POST(req: Request) {
  try {
    const ip = req.headers.get('x-forwarded-for') || 'anonymous';
    const isAllowed = await rateLimiter.check(`feedback_${ip}`);

    if (!isAllowed) {
      return NextResponse.json({ error: 'Too many feedback requests. Please try again later.' }, { status: 429 });
    }

    const parsed = FeedbackSchema.safeParse(await req.json());
    if (!parsed.success) {
      return NextResponse.json({ error: 'Invalid input', details: parsed.error }, { status: 400 });
    }
    const { threadId, messageContent, rating, comment, agent } = parsed.data;

    const supabase = createClient(
      process.env.NEXT_PUBLIC_SUPABASE_URL!,
      process.env.SUPABASE_SERVICE_ROLE_KEY!
    );

    const { error } = await supabase
      .from('ai_feedback')
      .insert([
        {
          thread_id: threadId,
          message_content: messageContent,
          rating,
          comment,
          agent
        }
      ]);

    if (error) {
      logger.error({ error }, 'Failed to insert AI feedback');
      return NextResponse.json({ error: 'Failed to record feedback' }, { status: 500 });
    }

    return NextResponse.json({ success: true });
  } catch (err: any) {
    logger.error({ err }, 'Error in feedback route');
    return NextResponse.json({ error: 'Internal Server Error' }, { status: 500 });
  }
}

import { NextRequest, NextResponse } from 'next/server';
import { createClient } from '@supabase/supabase-js';
import { z } from 'zod';

const supabase = createClient(
  process.env.NEXT_PUBLIC_SUPABASE_URL!,
  process.env.SUPABASE_SERVICE_ROLE_KEY!
);

const StatsQuerySchema = z.object({
  from: z.string().optional(),
  to: z.string().optional(),
  agent: z.string().optional(),
});

export async function GET(req: NextRequest) {
  try {
    const { searchParams } = new URL(req.url);
    const query = StatsQuerySchema.parse({
      from: searchParams.get('from') || undefined,
      to: searchParams.get('to') || undefined,
      agent: searchParams.get('agent') || undefined,
    });

    let dbQuery = supabase
      .from('ai_feedback')
      .select('id, created_at, rating, agent, message_content, comment');

    if (query.from) dbQuery = dbQuery.gte('created_at', query.from);
    if (query.to) dbQuery = dbQuery.lte('created_at', query.to);
    if (query.agent) dbQuery = dbQuery.eq('agent', query.agent);

    const { data, error } = await dbQuery;

    if (error) throw error;

    // === Summary KPIs ===
    const total = data.length;
    // Map 'up'/'down' to 'positive'/'negative' based on our schema
    const positive = data.filter((d) => d.rating === 'positive' || d.rating === 'up' || d.rating === 1).length;
    const negative = data.filter((d) => d.rating === 'negative' || d.rating === 'down' || d.rating === -1).length;
    const positiveRate = total > 0 ? Math.round((positive / total) * 100) : 0;

    // === Feedback by Agent ===
    const byAgent = Object.values(
      data.reduce((acc: any, item) => {
        const key = item.agent || 'unknown';
        if (!acc[key]) acc[key] = { agent: key, up: 0, down: 0, total: 0 };

        const isPositive = item.rating === 'positive' || item.rating === 'up' || item.rating === 1;
        acc[key][isPositive ? 'up' : 'down']++;
        acc[key].total++;
        return acc;
      }, {})
    );

    // === Trend Over Time (daily) ===
    const trendMap: Record<string, { date: string; up: number; down: number }> = {};
    data.forEach((item) => {
      const date = item.created_at.split('T')[0];
      if (!trendMap[date]) trendMap[date] = { date, up: 0, down: 0 };

      const isPositive = item.rating === 'positive' || item.rating === 'up' || item.rating === 1;
      trendMap[date][isPositive ? 'up' : 'down']++;
    });
    const trend = Object.values(trendMap).sort((a, b) => a.date.localeCompare(b.date));

    // === Needs Attention (recent negative feedback) ===
    const needsAttention = data
      .filter((d) => d.rating === 'negative' || d.rating === 'down' || d.rating === -1)
      .sort((a, b) => b.created_at.localeCompare(a.created_at))
      .slice(0, 10)
      .map((d) => ({
        id: d.id,
        created_at: d.created_at,
        agent: d.agent,
        query: d.message_content, // Map to what the frontend might expect
        response: d.message_content, // Map to what the frontend might expect
        review_status: 'pending', // Mocked if not present
      }));

    return NextResponse.json({
      summary: {
        total,
        positive,
        negative,
        positiveRate,
      },
      byAgent,
      trend,
      needsAttention,
    });
  } catch (error) {
    console.error('Feedback stats error:', error);
    return NextResponse.json({ error: 'Failed to fetch stats' }, { status: 500 });
  }
}

import { NextRequest, NextResponse } from 'next/server';
import { agentGraph } from '@/ai/graph';
import { HumanMessage } from '@langchain/core/messages';

export async function POST(req: NextRequest) {
  try {
    const body = await req.json();
    const { income, gestation, support, region } = body;

    const query = `I am a parent in ${region || 'New Zealand'}. 
My household income is ${income || 'unknown'}. 
My baby was born at ${gestation || 'unknown'} weeks gestation. 
Currently I am receiving: ${support || 'nothing'}. 
Please evaluate my eligibility for financial grants such as Best Start, WINZ, or Disability Allowance.`;

    const result = await agentGraph.invoke(
      {
        query,
        consentGiven: true,
        intent: 'EXECUTION',
        currentAgent: 'funding_eligibility_checker',
        messages: [new HumanMessage(query)],
      },
      {
        configurable: { thread_id: `financial_eval_${Date.now()}` },
      }
    );

    return NextResponse.json({ 
      success: true, 
      report: result.finalResponse,
      sources: result.sources || []
    });

  } catch (error: any) {
    console.error('API Route Error:', error);

    // If we hit the interrupt due to human review (which funding_eligibility_checker requires)
    if (error && (error.name === 'Interrupt' || error.name === 'GraphInterrupt')) {
      const interruptValue = error.value || error.interrupt || {};
      return NextResponse.json({ 
        success: true, 
        report: interruptValue.proposedResponse,
        note: 'This report was generated by AI and is pending human review by a financial counselor.'
      });
    }

    return NextResponse.json({ error: 'Internal Server Error' }, { status: 500 });
  }
}

