'use client';

import { useState, useEffect } from 'react';
import {
  BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, CartesianGrid,
  LineChart, Line, Legend
} from 'recharts';

interface FeedbackStats {
  summary: {
    total: number;
    positive: number;
    negative: number;
    positiveRate: number;
  };
  byAgent: Array<{
    agent: string;
    up: number;
    down: number;
    total: number;
  }>;
  trend: Array<{
    date: string;
    up: number;
    down: number;
  }>;
  needsAttention: Array<{
    id: string;
    created_at: string;
    agent: string;
    query: string;
    response: string;
    review_status: string;
  }>;
}

export function FeedbackAnalysisDashboard() {
  const [stats, setStats] = useState<FeedbackStats | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  const [filters, setFilters] = useState({
    from: '',
    to: '',
    agent: '',
  });

  const fetchStats = async () => {
    setLoading(true);
    setError(null);

    try {
      const params = new URLSearchParams();
      if (filters.from) params.append('from', filters.from);
      if (filters.to) params.append('to', filters.to);
      if (filters.agent) params.append('agent', filters.agent);

      const res = await fetch(`/api/feedback/stats?${params.toString()}`);
      if (!res.ok) throw new Error('Failed to load feedback data');

      const data = await res.json();
      setStats(data);
    } catch (err) {
      console.error(err);
      setError('Failed to load feedback analytics');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchStats();
  }, [filters]);

  if (loading && !stats) {
    return <div className="p-8 text-gray-500">Loading feedback insights...</div>;
  }

  if (error) {
    return <div className="p-8 text-red-600">{error}</div>;
  }

  if (!stats) return null;

  return (
    <div className="p-8 max-w-7xl mx-auto">
      <div className="flex justify-between items-center mb-8">
        <h1 className="text-3xl font-semibold">Feedback Analysis</h1>
        <button
          onClick={fetchStats}
          className="px-4 py-2 text-sm border rounded-lg hover:bg-gray-50"
        >
          Refresh Data
        </button>
      </div>

      {/* Summary KPIs */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-4 mb-8">
        <div className="bg-white p-6 rounded-2xl border">
          <div className="text-sm text-gray-500">Total Feedback</div>
          <div className="text-4xl font-semibold mt-2">{stats.summary.total}</div>
        </div>
        <div className="bg-white p-6 rounded-2xl border">
          <div className="text-sm text-gray-500">Positive Rate</div>
          <div className="text-4xl font-semibold mt-2 text-green-600">
            {stats.summary.positiveRate}%
          </div>
        </div>
        <div className="bg-white p-6 rounded-2xl border">
          <div className="text-sm text-gray-500">Positive</div>
          <div className="text-4xl font-semibold mt-2">{stats.summary.positive}</div>
        </div>
        <div className="bg-white p-6 rounded-2xl border">
          <div className="text-sm text-gray-500">Negative</div>
          <div className="text-4xl font-semibold mt-2 text-red-600">
            {stats.summary.negative}
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 mb-8">
        {/* Feedback by Agent */}
        <div className="bg-white p-6 rounded-2xl border">
          <h3 className="font-semibold mb-4">Feedback by Agent</h3>
          <div className="h-[320px] w-full">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={stats.byAgent}>
                <CartesianGrid strokeDasharray="3 3" />
                <XAxis dataKey="agent" />
                <YAxis />
                <Tooltip />
                <Legend />
                <Bar dataKey="up" name="Positive" stackId="a" fill="#22c55e" />
                <Bar dataKey="down" name="Negative" stackId="a" fill="#ef4444" />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        {/* Trend Over Time */}
        <div className="bg-white p-6 rounded-2xl border">
          <h3 className="font-semibold mb-4">Trend Over Time</h3>
          <div className="h-[320px] w-full">
            <ResponsiveContainer width="100%" height="100%">
              <LineChart data={stats.trend}>
                <CartesianGrid strokeDasharray="3 3" />
                <XAxis dataKey="date" />
                <YAxis />
                <Tooltip />
                <Legend />
                <Line type="monotone" dataKey="up" name="Positive" stroke="#22c55e" activeDot={{ r: 8 }} />
                <Line type="monotone" dataKey="down" name="Negative" stroke="#ef4444" activeDot={{ r: 8 }} />
              </LineChart>
            </ResponsiveContainer>
          </div>
        </div>
      </div>

      {/* Needs Attention */}
      <div className="bg-white p-6 rounded-2xl border">
        <h3 className="font-semibold mb-4">Needs Attention (Recent Negative Feedback)</h3>
        {stats.needsAttention.length > 0 ? (
          <div className="space-y-4">
            {stats.needsAttention.map((item) => (
              <div key={item.id} className="p-4 bg-red-50 border border-red-100 rounded-lg">
                <div className="flex justify-between mb-2">
                  <span className="font-semibold text-red-800">Agent: {item.agent || 'Unknown'}</span>
                  <span className="text-sm text-gray-500">{new Date(item.created_at).toLocaleString()}</span>
                </div>
                <div className="text-sm text-gray-700 mb-2">
                  <strong>Query:</strong> {item.query || 'N/A'}
                </div>
                <div className="text-sm text-gray-700">
                  <strong>Response:</strong> {item.response || 'N/A'}
                </div>
              </div>
            ))}
          </div>
        ) : (
          <p className="text-gray-500">No negative feedback recently.</p>
        )}
      </div>
    </div>
  );
}

'use client';

import React from 'react';
import {
  BarChart,
  Bar,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  Legend,
  ResponsiveContainer,
} from 'recharts';

export function FeedbackCharts({ feedbacks }: { feedbacks: any[] }) {
  // Process data for Feedback by Agent
  const agentStats = feedbacks.reduce((acc: any, fb: any) => {
    const agent = fb.agent || 'Unknown';
    if (!acc[agent]) {
      acc[agent] = { name: agent, positive: 0, negative: 0, total: 0 };
    }
    acc[agent].total += 1;
    if (fb.rating === 1 || fb.rating === 'positive') {
      acc[agent].positive += 1;
    } else {
      acc[agent].negative += 1;
    }
    return acc;
  }, {});

  const chartData = Object.values(agentStats);

  return (
    <div className="bg-white shadow rounded-lg p-6 mb-8 border border-gray-100">
      <h2 className="text-xl font-semibold mb-6">Feedback by Agent</h2>

      <div className="h-80 w-full mb-8">
        <ResponsiveContainer width="100%" height="100%">
          <BarChart data={chartData} margin={{ top: 20, right: 30, left: 20, bottom: 5 }}>
            <CartesianGrid strokeDasharray="3 3" />
            <XAxis dataKey="name" />
            <YAxis />
            <Tooltip />
            <Legend />
            <Bar dataKey="positive" name="Positive" stackId="a" fill="#22c55e" />
            <Bar dataKey="negative" name="Negative" stackId="a" fill="#ef4444" />
          </BarChart>
        </ResponsiveContainer>
      </div>

      <div className="overflow-x-auto">
        <table className="min-w-full divide-y divide-gray-200">
          <thead className="bg-gray-50">
            <tr>
              <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Agent</th>
              <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Total Feedback</th>
              <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Positive</th>
              <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Negative</th>
              <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Score</th>
            </tr>
          </thead>
          <tbody className="bg-white divide-y divide-gray-200">
            {chartData.map((stat: any) => (
              <tr key={stat.name}>
                <td className="px-6 py-4 whitespace-nowrap text-sm font-medium text-gray-900">{stat.name}</td>
                <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">{stat.total}</td>
                <td className="px-6 py-4 whitespace-nowrap text-sm text-green-600 font-semibold">{stat.positive}</td>
                <td className="px-6 py-4 whitespace-nowrap text-sm text-red-600 font-semibold">{stat.negative}</td>
                <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">
                  {stat.total > 0 ? Math.round((stat.positive / stat.total) * 100) + '%' : '-'}
                </td>
              </tr>
            ))}
            {chartData.length === 0 && (
              <tr>
                <td colSpan={5} className="px-6 py-4 text-center text-gray-500">No agent feedback data available</td>
              </tr>
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
}

