'use client';

import { useState } from 'react';

export function OrganisationUploadForm() {
  const [isLoading, setIsLoading] = useState(false);
  const [message, setMessage] = useState<{ type: 'success' | 'error'; text: string } | null>(null);

  const handleSubmit = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    setIsLoading(true);
    setMessage(null);

    const formData = new FormData(e.currentTarget);

    try {
      const res = await fetch('/api/upload/document', {
        method: 'POST',
        body: formData, // Sending raw FormData for multipart processing
      });

      if (!res.ok) throw new Error('Failed to upload document');

      setMessage({ type: 'success', text: 'Document uploaded and securely encrypted successfully.' });
      (e.target as HTMLFormElement).reset();
    } catch (err: any) {
      setMessage({ type: 'error', text: err.message || 'Something went wrong.' });
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <form onSubmit={handleSubmit} className="space-y-6 bg-white p-6 rounded-xl shadow border border-gray-100">
      <div>
        <h2 className="text-xl font-semibold text-gray-900">Secure Document Upload</h2>
        <p className="text-sm text-gray-500 mt-1">Upload clinical guidelines, forms, or resources. Files are encrypted by default via the Taonga Vault.</p>
      </div>

      {message && (
        <div role="alert" aria-live="polite" className={`p-4 rounded-lg text-sm ${message.type === 'success' ? 'bg-emerald-50 text-emerald-700 border border-emerald-200' : 'bg-red-50 text-red-700 border border-red-200'}`}>
          {message.text}
        </div>
      )}

      <div>
        <label htmlFor="file-upload" className="block text-sm font-medium text-gray-700 mb-1">Select File *</label>
        <input 
          id="file-upload"
          required 
          name="file" 
          type="file" 
          accept=".pdf,.doc,.docx,.txt"
          className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-emerald-500 outline-none transition file:mr-4 file:py-2 file:px-4 file:rounded-full file:border-0 file:text-sm file:font-semibold file:bg-emerald-50 file:text-emerald-700 hover:file:bg-emerald-100" 
        />
      </div>

      <div>
        <label htmlFor="filename-input" className="block text-sm font-medium text-gray-700 mb-1">Display Title (Optional)</label>
        <input id="filename-input" name="filename" type="text" className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-emerald-500 outline-none transition" placeholder="Leave blank to use original filename" />
      </div>

      <div className="flex items-start space-x-3 bg-gray-50 p-4 rounded-lg">
        <div className="flex items-center h-5">
          <input id="is_encrypted" defaultChecked name="is_encrypted" type="checkbox" className="w-4 h-4 text-emerald-600 rounded border-gray-300 focus:ring-emerald-500" />
        </div>
        <div className="flex-1 text-sm">
          <label htmlFor="is_encrypted" className="font-medium text-gray-700">Apply Taonga Vault Encryption</label>
          <p className="text-gray-500">Encrypt this file securely at rest. Note: Encrypted files cannot be processed by the AI RAG pipeline.</p>
        </div>
      </div>

      <button
        type="submit"
        disabled={isLoading}
        className="w-full bg-emerald-700 hover:bg-emerald-800 text-white font-medium py-3 rounded-lg transition disabled:opacity-50"
      >
        {isLoading ? 'Uploading...' : 'Securely Upload Document'}
      </button>
    </form>
  );
}

'use client';

import { useState } from 'react';
import { useRouter } from 'next/navigation';

export function StorySubmissionForm() {
  const [title, setTitle] = useState('');
  const [content, setContent] = useState('');
  const [tags, setTags] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [success, setSuccess] = useState(false);
  const [error, setError] = useState('');
  const router = useRouter();

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);
    setError('');
    setSuccess(false);

    try {
      const res = await fetch('/api/stories', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ 
          title, 
          content, 
          tags: tags.split(',').map(t => t.trim()).filter(Boolean) 
        }),
      });

      if (!res.ok) {
        throw new Error('Failed to submit story');
      }

      setSuccess(true);
      setTitle('');
      setContent('');
      setTags('');
      router.refresh();
    } catch (err: any) {
      setError(err.message);
    } finally {
      setIsSubmitting(false);
    }
  };

  if (success) {
    return (
      <div className="bg-green-50 text-green-800 p-6 rounded-lg text-center">
        <h3 className="text-xl font-bold mb-2">Thank you for sharing your story.</h3>
        <p>Your story has been submitted and is pending review by our moderation team to ensure cultural safety and appropriateness. It will appear here once approved.</p>
        <button onClick={() => setSuccess(false)} className="mt-4 text-green-700 underline">Submit another story</button>
      </div>
    );
  }

  return (
    <form onSubmit={handleSubmit} className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
      <h3 className="text-2xl font-semibold mb-4 text-gray-900">Share Your Story</h3>
      {error && <div className="mb-4 text-red-600 text-sm">{error}</div>}

      <div className="mb-4">
        <label htmlFor="title" className="block text-sm font-medium text-gray-700 mb-1">Title</label>
        <input 
          id="title"
          type="text" 
          required 
          value={title} 
          onChange={e => setTitle(e.target.value)}
          className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none" 
          placeholder="A brief title for your experience"
        />
      </div>

      <div className="mb-4">
        <label htmlFor="content" className="block text-sm font-medium text-gray-700 mb-1">Your Story</label>
        <textarea 
          id="content"
          required 
          rows={5}
          value={content} 
          onChange={e => setContent(e.target.value)}
          className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none resize-none" 
          placeholder="Share your journey..."
        />
      </div>

      <div className="mb-6">
        <label htmlFor="tags" className="block text-sm font-medium text-gray-700 mb-1">Tags (comma separated)</label>
        <input 
          id="tags"
          type="text" 
          value={tags} 
          onChange={e => setTags(e.target.value)}
          className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none" 
          placeholder="e.g. NICU, breastfeeding, twins"
        />
      </div>

      <button 
        type="submit" 
        disabled={isSubmitting}
        className="w-full bg-blue-600 text-white font-medium py-3 rounded-lg hover:bg-blue-700 disabled:opacity-50"
      >
        {isSubmitting ? 'Submitting...' : 'Submit Story Anonymously'}
      </button>
    </form>
  );
}

'use client';

import React from 'react';
import {
  LineChart,
  Line,
  BarChart,
  Bar,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  Legend,
  ResponsiveContainer,
  Cell,
} from 'recharts';

export function SystemMetricsCharts({ events }: { events: any[] }) {
  // Usage Spikes (Requests over time - grouped by hour)
  const usageMap: Record<string, number> = {};

  events.forEach(e => {
    if (e.created_at) {
      const date = new Date(e.created_at);
      // Format as "MM-DD HH:00"
      const month = String(date.getMonth() + 1).padStart(2, '0');
      const day = String(date.getDate()).padStart(2, '0');
      const hour = String(date.getHours()).padStart(2, '0');
      const key = `${month}-${day} ${hour}:00`;
      usageMap[key] = (usageMap[key] || 0) + 1;
    }
  });

  // Sort chronologically and take last 24 entries
  let usageData = Object.keys(usageMap)
    .sort()
    .map(key => ({ time: key, requests: usageMap[key] }))
    .slice(-24);

  // Fallback if no data
  if (usageData.length === 0) {
    usageData = [
      { time: 'No data', requests: 0 }
    ];
  }

  // Latency Monitoring (Average response time by agent)
  const latencyEvents = events.filter(e => e.event_type === 'agent_latency');
  const agentStats = latencyEvents.reduce((acc: any, ev: any) => {
    const agent = ev.metadata?.agent || 'Unknown';
    if (!acc[agent]) {
      acc[agent] = { name: agent, totalLatency: 0, count: 0 };
    }
    acc[agent].totalLatency += (ev.metadata?.durationMs || 0);
    acc[agent].count += 1;
    return acc;
  }, {});

  const latencyData = Object.values(agentStats).map((s: any) => ({
    name: s.name,
    avgLatency: Math.round(s.totalLatency / s.count)
  }));

  return (
    <div className="space-y-8">
      {/* Usage Chart */}
      <div className="bg-white shadow rounded-lg p-6 border border-gray-100">
        <h2 className="text-xl font-semibold mb-6">Usage Spikes (Last 24 Hours)</h2>
        <div className="h-72 w-full">
          <ResponsiveContainer width="100%" height="100%">
            <LineChart data={usageData} margin={{ top: 20, right: 30, left: 20, bottom: 5 }}>
              <CartesianGrid strokeDasharray="3 3" />
              <XAxis dataKey="time" />
              <YAxis />
              <Tooltip />
              <Legend />
              <Line type="monotone" dataKey="requests" name="Total Requests" stroke="#3b82f6" activeDot={{ r: 8 }} />
            </LineChart>
          </ResponsiveContainer>
        </div>
      </div>

      {/* Latency Chart */}
      <div className="bg-white shadow rounded-lg p-6 border border-gray-100">
        <h2 className="text-xl font-semibold mb-6">Average Latency by Agent (ms)</h2>
        <div className="h-72 w-full">
          {latencyData.length > 0 ? (
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={latencyData} margin={{ top: 20, right: 30, left: 20, bottom: 5 }}>
                <CartesianGrid strokeDasharray="3 3" />
                <XAxis dataKey="name" />
                <YAxis />
                <Tooltip />
                <Legend />
                <Bar dataKey="avgLatency" name="Latency (ms)">
                  {
                    latencyData.map((entry, index) => (
                      <Cell key={`cell-${index}`} fill={entry.avgLatency > 5000 ? '#ef4444' : '#8b5cf6'} />
                    ))
                  }
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          ) : (
            <div className="flex items-center justify-center h-full text-gray-500">
              No latency data recorded yet.
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

