'use client';

import React, { useState, useEffect } from 'react';

export function WelcomeModal() {
  const [isOpen, setIsOpen] = useState(false);

  useEffect(() => {
    const hasSeen = localStorage.getItem('hasSeenBetaWelcome');
    if (!hasSeen) {
      setIsOpen(true);
    }
  }, []);

  const handleAccept = () => {
    localStorage.setItem('hasSeenBetaWelcome', 'true');
    setIsOpen(false);
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black bg-opacity-50 px-4">
      <div className="bg-white rounded-2xl shadow-xl max-w-lg w-full p-6 animate-in fade-in zoom-in duration-200">
        <h2 className="text-2xl font-bold text-gray-900 mb-4">Welcome to the Beta! 👋</h2>

        <div className="space-y-4 text-gray-600 text-sm mb-6">
          <p>
            You are testing the <strong>Front Line Whānau Assistant</strong>. We're so glad you're here to help us shape this tool!
          </p>
          <div className="bg-amber-50 border border-amber-200 rounded-lg p-4 text-amber-800">
            <strong>⚠️ Important Medical Disclaimer</strong>
            <p className="mt-1">
              This AI is an experimental support tool and is <strong>NOT</strong> a doctor. It cannot diagnose or provide medical advice. Always call 111 in an emergency, or PlunketLine/Healthline for urgent medical questions.
            </p>
          </div>
          <p>
            By continuing, you agree that your feedback (Thumbs Up/Down) may be reviewed by practitioners to improve the system.
          </p>
        </div>

        <button
          onClick={handleAccept}
          className="w-full py-3 bg-blue-600 text-white font-semibold rounded-xl hover:bg-blue-700 transition shadow-sm"
        >
          I Understand & Agree
        </button>
      </div>
    </div>
  );
}

'use client';

import { useEffect } from 'react';
import { usePathname } from 'next/navigation';

export function useAnalytics() {
  const pathname = usePathname();

  const trackEvent = async (eventType: string, metadata: Record<string, any> = {}) => {
    try {
      await fetch('/api/analytics/track', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          event_type: eventType,
          path: window.location.pathname,
          metadata
        })
      });
    } catch (err) {
      // Ignore analytics tracking errors silently
      console.warn('Analytics tracking failed', err);
    }
  };

  useEffect(() => {
    // Automatically track page views when the pathname changes
    if (pathname) {
      trackEvent('page_view');
    }
  }, [pathname]);

  return { trackEvent };
}

