import { useState, useEffect } from 'react';

// Hook for Stopwatch (count up)
export function useStopwatch(storageKey: string) {
  const [isRunning, setIsRunning] = useState(false);
  const [elapsedMs, setElapsedMs] = useState(0);
  const [startTime, setStartTime] = useState<number | null>(null);

  useEffect(() => {
    const saved = localStorage.getItem(storageKey);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        if (parsed.isRunning && parsed.startTime) {
          setIsRunning(true);
          setStartTime(parsed.startTime);
          setElapsedMs(parsed.elapsedMs + (Date.now() - parsed.startTime));
        } else {
          setElapsedMs(parsed.elapsedMs);
        }
      } catch (e) {}
    }
  }, [storageKey]);

  useEffect(() => {
    let interval: NodeJS.Timeout;
    if (isRunning) {
      interval = setInterval(() => {
        if (startTime) {
          setElapsedMs(prev => prev + 1000);
        }
      }, 1000);
    }
    return () => clearInterval(interval);
  }, [isRunning, startTime]);

  useEffect(() => {
    // Save to local storage whenever critical state changes
    if (startTime !== null || elapsedMs > 0) {
      localStorage.setItem(storageKey, JSON.stringify({ isRunning, startTime, elapsedMs }));
    }
  }, [isRunning, startTime, elapsedMs, storageKey]);

  const start = () => {
    setIsRunning(true);
    setStartTime(Date.now());
  };

  const stop = () => {
    setIsRunning(false);
    setStartTime(null);
  };

  const reset = () => {
    setIsRunning(false);
    setStartTime(null);
    setElapsedMs(0);
    localStorage.removeItem(storageKey);
  };

  const formatTime = (ms: number) => {
    const totalSeconds = Math.floor(ms / 1000);
    const hours = Math.floor(totalSeconds / 3600);
    const minutes = Math.floor((totalSeconds % 3600) / 60);
    const seconds = totalSeconds % 60;

    if (hours > 0) {
      return `${hours}:${minutes.toString().padStart(2, '0')}:${seconds.toString().padStart(2, '0')}`;
    }
    return `${minutes.toString().padStart(2, '0')}:${seconds.toString().padStart(2, '0')}`;
  };

  return { isRunning, elapsedMs, start, stop, reset, formatTime };
}

// Hook for Countdown (count down from target)
export function useCountdown(storageKey: string, initialMinutes: number) {
  const [isRunning, setIsRunning] = useState(false);
  const [remainingMs, setRemainingMs] = useState(initialMinutes * 60 * 1000);
  const [endTime, setEndTime] = useState<number | null>(null);

  useEffect(() => {
    const saved = localStorage.getItem(storageKey);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        if (parsed.isRunning && parsed.endTime) {
          const now = Date.now();
          if (now < parsed.endTime) {
            setIsRunning(true);
            setEndTime(parsed.endTime);
            setRemainingMs(parsed.endTime - now);
          } else {
            // Timer finished while away
            setIsRunning(false);
            setRemainingMs(0);
            setEndTime(null);
          }
        } else {
          setRemainingMs(parsed.remainingMs);
        }
      } catch (e) {}
    }
  }, [storageKey]);

  useEffect(() => {
    let interval: NodeJS.Timeout;
    if (isRunning && endTime) {
      interval = setInterval(() => {
        const now = Date.now();
        if (now >= endTime) {
          setIsRunning(false);
          setRemainingMs(0);
          setEndTime(null);
          clearInterval(interval);
          // Optional: Play a sound or show notification here in the future
        } else {
          setRemainingMs(endTime - now);
        }
      }, 1000);
    }
    return () => clearInterval(interval);
  }, [isRunning, endTime]);

  useEffect(() => {
    if (endTime !== null || remainingMs !== initialMinutes * 60 * 1000) {
      localStorage.setItem(storageKey, JSON.stringify({ isRunning, endTime, remainingMs }));
    }
  }, [isRunning, endTime, remainingMs, storageKey, initialMinutes]);

  const start = () => {
    setIsRunning(true);
    setEndTime(Date.now() + remainingMs);
  };

  const stop = () => {
    setIsRunning(false);
    setEndTime(null);
  };

  const reset = () => {
    setIsRunning(false);
    setEndTime(null);
    setRemainingMs(initialMinutes * 60 * 1000);
    localStorage.removeItem(storageKey);
  };

  const formatTime = (ms: number) => {
    const totalSeconds = Math.ceil(ms / 1000); // use ceil so it doesn't show 0 too early
    const minutes = Math.floor(totalSeconds / 60);
    const seconds = totalSeconds % 60;
    return `${minutes.toString().padStart(2, '0')}:${seconds.toString().padStart(2, '0')}`;
  };

  return { isRunning, remainingMs, start, stop, reset, formatTime };
}

import { logger } from './logger';

interface CacheEntry<T> {
  value: T;
  expiry: number;
}

export class MemoryCache {
  private cache = new Map<string, CacheEntry<any>>();

  constructor(private defaultTTLMs: number = 3600000) {} // Default 1 hour TTL

  get<T>(key: string): T | null {
    const entry = this.cache.get(key);
    if (!entry) return null;

    if (Date.now() > entry.expiry) {
      this.cache.delete(key);
      return null;
    }
    return entry.value as T;
  }

  set<T>(key: string, value: T, ttlMs?: number): void {
    const expiry = Date.now() + (ttlMs || this.defaultTTLMs);
    this.cache.set(key, { value, expiry });
  }

  delete(key: string): void {
    this.cache.delete(key);
  }

  clear(): void {
    this.cache.clear();
  }

  /**
   * Helper to wrap an async function with caching
   */
  async withCache<T>(key: string, fn: () => Promise<T>, ttlMs?: number): Promise<T> {
    const cached = this.get<T>(key);
    if (cached !== null) {
      logger.info({ cacheKey: key }, 'Cache HIT');
      return cached;
    }
    logger.info({ cacheKey: key }, 'Cache MISS. Executing function.');
    const result = await fn();
    this.set(key, result, ttlMs);
    return result;
  }
}

// Global cache instance
export const aiToolCache = new MemoryCache();

/**
 * Server-side structured logger — pino
 *
 * Usage (server components, API routes, middleware):
 *   import { logger } from '@/lib/logger';
 *   logger.info({ route: '/api/health' }, 'Health check called');
 *   logger.error({ err }, 'Unexpected error in agent route');
 *
 * Rules:
 *   - Never log: passphrases, encryption keys, journal content, health data
 *   - Only log: route names, error codes, timing, AI agent state transitions
 *   - Logs are structured JSON in production (parseable by Vercel / Datadog)
 *   - Logs are pretty-printed in development
 */

import pino from 'pino';

// Fire-and-forget webhook alert for catastrophic failures
const FIRE_WEBHOOK_ALERT = async (msg: string, obj: any) => {
  const webhookUrl = process.env.SLACK_WEBHOOK_URL || process.env.DISCORD_WEBHOOK_URL;
  if (!webhookUrl) return;

  try {
    await fetch(webhookUrl, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        text: `🚨 *CRITICAL ALERT* 🚨\n${msg}\n\`\`\`json\n${JSON.stringify(obj, null, 2)}\n\`\`\``
      })
    });
  } catch (e) {
    console.error("Failed to fire alert webhook", e);
  }
};

const isDev = process.env.NODE_ENV !== 'production';

export const logger = pino({
  level: process.env.LOG_LEVEL ?? (isDev ? 'debug' : 'info'),

  // In development: pretty-print for human readability
  // In production: plain JSON for log aggregation services
  transport: isDev
    ? { target: 'pino-pretty', options: { colorize: true, translateTime: 'HH:MM:ss' } }
    : undefined,

  hooks: {
    logMethod(inputArgs, method, level) {
      if (level === 50) { // Error level
        const [obj, msg] = inputArgs.length >= 2 ? [inputArgs[0], inputArgs[1]] : [{}, inputArgs[0]];
        if (typeof obj === 'object') {
          if (msg) console.error(msg, obj);
          else console.error(obj);
        } else {
          console.error(obj, msg);
        }

        // Trigger webhook on fatal errors or circuit breaker trips
        if (typeof msg === 'string' && (msg.toLowerCase().includes('fatal') || msg.toLowerCase().includes('circuit breaker'))) {
          FIRE_WEBHOOK_ALERT(msg, obj).catch(() => {});
        }
      }
      return method.apply(this, inputArgs as any);
    }
  },

  // Redact fields that must never appear in logs
  redact: {
    paths: [
      'passphrase',
      'password',
      'key',
      'secret',
      'token',
      'SUPABASE_SERVICE_ROLE_KEY',
      'GOOGLE_API_KEY',
      'content',         // journal/vault content
      'plaintext',
      'ciphertext',
      'body.passphrase',
      'body.password',
    ],
    censor: '[REDACTED]',
  },

  // Base fields on every log line
  base: {
    app: 'front-line-whanau',
    version: process.env.NEXT_PUBLIC_APP_VERSION ?? 'unknown',
    env: process.env.NODE_ENV ?? 'development',
  },
});

/** Child logger for a specific route or module. */
export function routeLogger(route: string) {
  return logger.child({ route });
}

/** Child logger for AI agent operations. */
export function agentLogger(agentName: string) {
  return logger.child({ agent: agentName });
}

import { Ratelimit } from '@upstash/ratelimit';
import { Redis } from '@upstash/redis';

export class RateLimiter {
  private store = new Map<string, number[]>();
  private windowMs: number;
  private maxRequests: number;
  private upstashRatelimit?: Ratelimit;

  constructor(windowMs: number, maxRequests: number) {
    this.windowMs = windowMs;
    this.maxRequests = maxRequests;

    if (process.env.UPSTASH_REDIS_REST_URL && process.env.UPSTASH_REDIS_REST_TOKEN) {
      try {
        const redis = new Redis({
          url: process.env.UPSTASH_REDIS_REST_URL,
          token: process.env.UPSTASH_REDIS_REST_TOKEN,
        });

        // @ts-ignore - Upstash types might be strict about time units, 'ms' is supported
        this.upstashRatelimit = new Ratelimit({
          redis,
          limiter: Ratelimit.slidingWindow(maxRequests, `${windowMs} ms`),
        });
      } catch (e) {
        console.warn('Failed to initialize Upstash Redis rate limiter, falling back to in-memory.', e);
      }
    }
  }

  async check(key: string): Promise<boolean> {
    if (this.upstashRatelimit) {
      try {
        const { success } = await this.upstashRatelimit.limit(key);
        return success;
      } catch (e) {
        console.error("Upstash Rate Limit error, falling back to in-memory", e);
      }
    }

    const now = Date.now();
    const timestamps = this.store.get(key) || [];
    const recent = timestamps.filter(ts => now - ts < this.windowMs);

    if (recent.length >= this.maxRequests) return false;

    recent.push(now);
    this.store.set(key, recent);
    return true;
  }
}

/**
 * Centralized structured logger for production monitoring.
 * Outputs JSON so it can be easily ingested by Datadog, CloudWatch, Vercel, or Sentry.
 */

type LogLevel = 'info' | 'warn' | 'error' | 'metric';

interface LogPayload {
  message: string;
  [key: string]: any;
}

class TelemetryLogger {
  private format(level: LogLevel, payload: LogPayload | string, error?: unknown) {
    const timestamp = new Date().toISOString();

    let base: any = {
      timestamp,
      level,
      environment: process.env.NODE_ENV || 'development'
    };

    if (typeof payload === 'string') {
      base.message = payload;
    } else {
      base = { ...base, ...payload };
    }

    if (error) {
      if (error instanceof Error) {
        base.error = {
          message: error.message,
          stack: error.stack,
          name: error.name
        };
      } else {
        base.error = error;
      }
    }

    return JSON.stringify(base);
  }

  info(payload: LogPayload | string) {
    console.log(this.format('info', payload));
  }

  warn(payload: LogPayload | string) {
    console.warn(this.format('warn', payload));
  }

  error(payload: LogPayload | string, error?: unknown) {
    console.error(this.format('error', payload, error));
  }

  metric(name: string, value: number, tags: Record<string, any> = {}) {
    console.log(this.format('metric', { message: `Metric: ${name}`, metric_name: name, metric_value: value, ...tags }));
  }
}

export const logger = new TelemetryLogger();
